/**
 * Cook build config for the Vanilla Breeze documentation site.
 */
export default {
  srcPath: 'src',
  distPath: 'dist',

  // Sitemap is generated by scripts/generate-sitemap.js after assemble-site.js,
  // because Cook's built-in plugin scans dist/ rather than dist/pages/ and
  // can't strip the leading /pages/ from URLs. Leaving this block out keeps
  // the Cook plugin disabled (its early-exit triggers on missing sitemap.url).

  // Directories that are used during build but not copied to dist
  buildOnlyPaths: ['layouts', 'includes'],

  // Custom plugins
  plugins: {
    before: ['generate-sidebars', 'generate-topics'],
    // generate-api-tables must run before auto-link-glossary: api-tables
    // strips legacy `{% from "partials/attribute-table.njk" %}` import
    // lines. If auto-link runs first, it wraps the word "attribute" inside
    // those literals with <dfn><a href="...">, embedding `"` characters into
    // the import path. That breaks api-tables' strip regex (which expects a
    // clean quoted string), so the directive survives to the rendered HTML
    // and trips audit-unresolved-templates.
    default: ['generate-provenance-meta', 'generate-api-tables', 'auto-link-glossary', 'generate-indexes', 'render-dynamic-pages', 'generate-glossary'],
    after: ['generate-pages-json', 'generate-definitions-json', 'generate-topic-assets'],
  },
  pluginPath: 'plugins',

  // Disable features not needed for PoC
  images: { enabled: false },
  formats: { markdown: false, json: false, feed: null, llmsTxt: false },
  fragments: { enabled: false },

  // Components path (if we need Cook components)
  components: {
    path: 'components',
  },
};
